export default function MIcon({
  name,
  size = 24,
  fill = false,
  className,
  style,
  "aria-hidden": ariaHidden = true,
}: {
  name: string;
  size?: number;
  fill?: boolean;
  className?: string;
  style?: React.CSSProperties;
  "aria-hidden"?: boolean;
}) {
  const map = fill ? FILLED : OUTLINED;
  const icon = map[name] ?? OUTLINED[name];
  if (!icon) return null;
  return (
    <svg
      xmlns="http://www.w3.org/2000/svg"
      viewBox={icon.viewBox}
      width={size}
      height={size}
      fill="currentColor"
      className={className}
      style={style}
      aria-hidden={ariaHidden}
      focusable="false"
    >
      {icon.d.map((d, i) => <path key={i} d={d} />)}
    </svg>
  );
}